#include<bits/stdc++.h>
using namespace std;
long long a[1000010],b[1000010],lst[1000010];
constexpr long long mod=1e9+7;
struct segment_tree
{
	struct node
	{
		long long l,r,lson,rson;
		long long sum,pfsum,tag;
	}a[3000010];
	long long cnt;
	segment_tree():cnt(0){}
	void pushup(long long x)
	{
		a[x].sum=(a[a[x].lson].sum+a[a[x].rson].sum)%mod;
		a[x].pfsum=(a[a[x].lson].pfsum+a[a[x].rson].pfsum)%mod;
	}
	void pushadd(long long x,long long val)
	{
		a[x].pfsum+=2*a[x].sum%mod*val%mod+(a[x].r-a[x].l+1)*(val*val%mod)%mod;
		a[x].sum+=(a[x].r-a[x].l+1)*val%mod;
		a[x].tag+=val;
		a[x].pfsum%=mod;
		a[x].sum%=mod;
		a[x].tag%=mod;
	}
	void pushdown(long long x)
	{
		if(a[x].tag==0)
		{
			return;
		}
		pushadd(a[x].lson,a[x].tag);
		pushadd(a[x].rson,a[x].tag);
		a[x].tag=0;
	}
	long long init(long long l,long long r)
	{
		long long x=++cnt;
		a[x].l=l;
		a[x].r=r;
		a[x].tag=0;
		if(l==r)
		{
			a[x].sum=0;
			a[x].pfsum=0;
			return x;
		}
		long long mid=(l+r)>>1;
		a[x].lson=init(l,mid);
		a[x].rson=init(mid+1,r);
		pushup(x);
		return x;
	}
	void add(long long x,long long l,long long r,long long val)
	{
		if(a[x].l>r||a[x].r<l)
		{
			return;
		}
		if(l<=a[x].l&&a[x].r<=r)
		{
			pushadd(x,val);
			return;
		}
		pushdown(x);
		add(a[x].lson,l,r,val);
		add(a[x].rson,l,r,val);
		pushup(x);
	}
	long long getsum(long long x,long long l,long long r)
	{
		if(a[x].l>r||a[x].r<l)
		{
			return 0;
		}
		if(l<=a[x].l&&a[x].r<=r)
		{
			return a[x].sum;
		}
		pushdown(x);
		return (getsum(a[x].lson,l,r)+getsum(a[x].rson,l,r))%mod;
	}
	long long getpfsum(long long x,long long l,long long r)
	{
		if(a[x].l>r||a[x].r<l)
		{
			return 0;
		}
		if(l<=a[x].l&&a[x].r<=r)
		{
			return a[x].pfsum;
		}
		pushdown(x);
		return (getpfsum(a[x].lson,l,r)+getpfsum(a[x].rson,l,r))%mod;
	}
}t;
int main()
{
	long long n;
	scanf("%lld",&n);
	for(long long i=1;i<=n;i++)
	{
		scanf("%lld",&a[i]);
		b[i]=a[i];
	}
	sort(a+1,a+1+n);
	long long k=unique(a+1,a+1+n)-a-1;
	for(long long i=1;i<=n;i++)
	{
		b[i]=lower_bound(a+1,a+1+k,b[i])-a;
	}
	t.init(1,n);
	long long ans=0;
	for(long long i=1;i<=n;i++)
	{
		if(lst[b[i]])
		{
			t.add(1,lst[b[i]]+1,i,1);
		}
		else
		{
			t.add(1,1,i,1);
		}
		lst[b[i]]=i;
		ans+=t.getpfsum(1,1,i);
		ans%=mod;
	}
	printf("%lld",ans);
	return 0;
}
